use amd_sev_snp_attestation_prover::KDS;
use amd_sev_snp_attestation_verifier::AttestationReport;
use hex;
use sha2::{Digest, Sha256};
use x509_verifier_rust_crypto::CertChain;

fn main() -> anyhow::Result<()> {
    let quote_hex = std::env::args().nth(1)
        .unwrap_or_else(|| "".to_string());

    let quote_bytes = hex::decode(&quote_hex)?;
    println!("Quote bytes length: {}", quote_bytes.len());

    let report = AttestationReport::from_bytes(&quote_bytes)?;
    let processor = report.get_cpu_codename()?;

    println!("Processor model: {:?}", processor);
    println!("Processor model string: {}", processor.to_str()?);

    let kds = KDS::new();
    let cert_chain = kds.fetch_model_cert_chain(processor)?;

    println!("\nCert chain from KDS (ASK, ARK):");
    for (i, der) in cert_chain.iter().enumerate() {
        let hash = Sha256::digest(der.as_ref());
        println!(
            "  Cert {}: {} bytes, hash = 0x{}",
            i,
            der.len(),
            hex::encode(hash)
        );
    }

    // Now get the full chain with VCEK
    let full_chain = kds.fetch_report_cert_chain(&report)?;
    println!("\nFull cert chain (VCEK, ASK, ARK):");
    for (i, der) in full_chain.iter().enumerate() {
        let hash = Sha256::digest(der.as_ref());
        println!(
            "  Cert {}: {} bytes, hash = 0x{}",
            i,
            der.len(),
            hex::encode(hash)
        );
    }

    // Parse with parse_rev to get the path digests
    let parsed = CertChain::parse_rev(&full_chain)?;
    println!("\nCertChain path_digest (after parse_rev):");
    for (i, digest) in parsed.digest().iter().enumerate() {
        println!("  path_digest[{}] = 0x{}", i, hex::encode(digest));
    }

    Ok(())
}
